import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        freq = [0] * (n + 1)
        for x in arr:
            freq[x] += 1
        repeating = missing = -1
        for i in range(1, n + 1):
            if freq[i] == 0:
                missing = i
            elif freq[i] == 2:
                repeating = i
        out.append(f"{repeating} {missing}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

